={{(() => {
  let text = $('trataDados').first().json.message.content || '';

  // Converte para string
  text = String(text);

  // Remove caracteres de controle e quebras de linha
  text = text.replace(/[\n\r\t]/g, ' ');

  // Escapa aspas duplas e barras invertidas
  text = text.replace(/\\/g, '\\\\').replace(/"/g, '\\"');

  // Remove caracteres não imprimíveis do ASCII
  text = text.replace(/[^\x20-\x7E]+/g, '');

  return text;
})()}}

